entries.content:
Remove points below a certain height:
if (@P.y < chf('threshold')) {
    removepoint(0, @ptnum);
}

Count neighbors within a radius using point clouds:
int handle = pcopen(0, 'P', @P, chf('radius'), 1000);
i@neighbors = pcnumfound(handle);
pcclose(handle);

Apply a random rotation around the Y axis:
float angle = rand(@ptnum) * 3.6e2;
vector axis = {0,1,0};
@orient = qconvert(quaternion(radians(angle), axis));

Create a spiral point distribution:
float angle = @ptnum * chf('angle_step');
float r = @ptnum * chf('radius_step');
@P = set(cos(angle)*r, 0, sin(angle)*r);

Transfer Cd from the closest point in the second input:
int near = nearpoint(1, @P);
@Cd = point(1, 'Cd', near);

Smooth geometry by averaging neighbor positions:
int neighbors[] = neighbours(0, @ptnum);
vector avg_p = {0,0,0};
foreach (int nb; neighbors) {
    avg_p += point(0, 'P', nb);
}
@P = avg_p / len(neighbors);

Identify points on the boundary of a mesh (assuming grid-like topology):
if (neighbourcount(0, @ptnum) < 4) {
    i@is_edge = 1;
}

Assign points to a group randomly based on a probability slider:
if (rand(@ptnum + chf('seed')) < chf('prob')) {
    setpointgroup(0, 'selected', @ptnum, 1);
}

Use a custom ramp UI to control pscale based on X position:
float t = fit01(clamp(@P.x, -1, 1), 0, 1);
@pscale = chramp('my_ramp', t);

Simple approximation of an attribute gradient:
int pts[] = nearpoints(0, @P, chf('dist'), 8);
vector grad = {0,0,0};
foreach (int p; pts) {
    float val = point(0, 'mask', p);
    grad += (point(0, 'P', p) - @P) * (val - f@mask);
}
@N = normalize(grad);

Calculate the center of the bounding box:
vector min, max;
getbbox(0, min, max);
vector center = (min + max) * 0.5;
@P -= center;

Rotate the normal around arbitrary axis:
matrix3 m = ident();
rotate(m, radians(chf('angle')), normalize(chv('axis')));
@N *= m;

Sum values in an array attribute:
float total = 0;
foreach (float v; f[]@my_array) {
    total += v;
}
f@sum = total;

Get distance and primitive info to closest geometry in input 1:
int prim;
vector uv;
float dist = xyzdist(1, @P, prim, uv);
f@dist_to_surface = dist;

Sample UVs from second input based on closest point:
int prim;
vector uv;
xyzdist(1, @P, prim, uv);
@uv = primuv(1, 'uv', prim, uv);

Check if a bit flag is set:
if (i@flags & 1) {
    i@is_active = 1;
}

Store and retrieve values from a VEX dictionary:
dict my_dict = dict();
setdictvalue(my_dict, 'level', 5);
setdictvalue(my_dict, 'state', 'active');
i@lvl = getdictvalue(my_dict, 'level');

Calculate normalized direction to a goal point:
vector goal = chv('goal_pos');
@v = normalize(goal - @P) * chf('speed');

Simple bounce logic: reverse velocity on hitting floor:
if (@P.y < 0) {
    @P.y = 0;
    @v.y = -@v.y * chf('damp');
}

Rough curvature check based on normal deviation of neighbors:
int nbs[] = neighbours(0, @ptnum);
float avg_dot = 0;
foreach (int nb; nbs) {
    vector nb_n = point(0, 'N', nb);
    avg_dot += dot(@N, nb_n);
}
f@curvature = 1.0 - (avg_dot / len(nbs));

Delete primitives with near-zero area:
if (prim_area(0, @primnum) < 1e-5) {
    removeprim(0, @primnum, 1);
}

Blend position between input 0 and input 1:
vector p1 = point(1, 'P', @ptnum);
@P = lerp(@P, p1, chf('blend'));

Create a smooth transition mask:
float val = @P.x;
f@mask = smoothstep(chf('min'), chf('max'), val);

Apply a checkerboard pattern based on grid position:
int ix = int(floor(@P.x * chf('freq')));
int iz = int(floor(@P.z * chf('freq')));
@Cd = (ix + iz) % 2 == 0 ? set(1,1,1) : set(0,0,0);

Manual normal calculation for a triangle primitive:
int pts[] = primpoints(0, @primnum);
vector a = point(0, 'P', pts[0]);
vector b = point(0, 'P', pts[1]);
vector c = point(0, 'P', pts[2]);
@N = normalize(cross(b-a, c-a));

Offset primitives from centroid for an exploded view:
vector center = getbbox_center(0);
vector p_center = primintrinsic(0, 'centroid', @primnum);
vector dir = normalize(p_center - center);
@P += dir * chf('scale');

Remove points outside a simplified camera field:
vector p_cam = ptransform('obj/cam1', @P);
if (abs(p_cam.x) > 1.0 || abs(p_cam.y) > 1.0) {
    removepoint(0, @ptnum);
}

Calculate the average position and add a point there (run on detail):
vector avg = {0,0,0};
for (int i=0; i<npoints(0); ++i) {
    avg += point(0, 'P', i);
}
addpoint(0, avg / npoints(0));

Add 3D noise to a volume density (run on volume points):
float n = noise(@P * chf('freq'));
f@density *= clamp(n - chf('bias'), 0, 1);

Lookup value from input 1 using stable IDs:
int other_pt = findattribval(1, 'point', 'id', i@id);
if (other_pt != -1) @Cd = point(1, 'Cd', other_pt);

Connect points in order with a polygon (run once on detail):
int pr = addprim(0, 'poly');
for(int i=0; i<npoints(0); ++i) {
    addvertex(0, pr, i);
}

Test if point P is within the bounds of input 1:
vector mi, ma;
getbbox(1, mi, ma);
if (@P.x >= mi.x && @P.x <= ma.x && ...) i@inside = 1;

Direction from this point to the next along curve:
int next = (@ptnum + 1) % npoints(0);
@v = normalize(point(0, 'P', next) - @P);

Generate a force towards the closest part of a curve:
int pr; vector uv;
xyzdist(1, @P, pr, uv);
vector surf_p = primuv(1, 'P', pr, uv);
@v += normalize(surf_p - @P) * chf('strength');

Remove points with attribute below average (run detail first to get mean):
float mean = detail(0, 'mean_val');
if (f@value < mean) removepoint(0, @ptnum);

Apply global rotation to geometry:
matrix3 m = ident();
rotate(m, radians(@Time * 90), {0,1,0});
@P *= m;

Simple spherical UV mapping:
vector n = normalize(@P);
@uv = set(atan2(n.z, n.x)/(2*PI)+0.5, asin(n.y)/PI+0.5, 0);

Find the maximum pscale in the geometry:
float max_val = -1e10;
for(int i=0; i<npoints(0); ++i) {
    max_val = max(max_val, point(0, 'pscale', i));
}
f@max_pscale = max_val;

Get the center position of the nearest Voronoi cell:
vector cell_center;
wnoise(@P, 0, cell_center);
@Cd = cell_center;

Check if point is inside a world-space sphere:
if (distance(@P, chv('origin')) < chf('radius')) {
    i@active = 1;
}

Detect points in 'valleys' by checking neighbor distance to average plane:
vector avg_nb = {0,0,0};
int nbs[] = neighbours(0, @ptnum);
foreach(int n; nbs) avg_nb += point(0, 'P', n);
avg_nb /= len(nbs);
if (dot(@N, normalize(avg_nb - @P)) > 0.1) i@concave = 1;

Blur an attribute by averaging with neighbors:
float total = f@temp;
int nbs[] = neighbours(0, @ptnum);
foreach(int n; nbs) total += point(0, 'temp', n);
f@temp = total / (len(nbs) + 1);

Group triangles vs quads:
int count = primvertexcount(0, @primnum);
if (count == 3) setprimgroup(0, 'tris', @primnum, 1);
else if (count == 4) setprimgroup(0, 'quads', @primnum, 1);

Manually build a rotation matrix:
matrix3 m = ident();
rotate(m, radians(45), {0,1,0});

Snap points to closest surface location in input 1:
int pr; vector uv;
xyzdist(1, @P, pr, uv);
@P = primuv(1, 'P', pr, uv);

Assign a completely random orientation to each point:
@orient = set(rand(@ptnum)-0.5, rand(@ptnum+1)-0.5, rand(@ptnum+2)-0.5, rand(@ptnum+3)-0.5);
@orient = normalize(@orient);

Set pscale based on surrounding face area (approx):
float area = 0;
int prims[] = pointprims(0, @ptnum);
foreach(int p; prims) area += prim_area(0, p);
@pscale = sqrt(area) * 0.5;

Calculate how close point is to the edge of the scene:
vector mi, ma;
getbbox(0, mi, ma);
float dx = min(@P.x - mi.x, ma.x - @P.x);
float dz = min(@P.z - mi.z, ma.z - @P.z);
f@dist_to_edge = min(dx, dz);

Create expansion ripples from origin:
float dist = length(@P);
@P += normalize(@P) * sin(dist * 10 - @Time) * 0.1;

Pick a random name from a hardcoded list:
string names[] = {'red', 'blue', 'green'};
s@c_name = names[int(rand(@ptnum) * len(names))];

Verify if prim points all lie on the same plane:
int pts[] = primpoints(0, @primnum);
vector n = prim_normal(0, @primnum, {0,0,0});
float error = 0;
foreach(int p; pts) error += abs(dot(n, point(0, 'P', p) - point(0,'P',pts[0])));
if (error < 1e-4) i@is_flat = 1;

Identify points sharing roughly the same space:
int pts[] = nearpoints(0, @P, 0.001, 2);
if (len(pts) > 1) i@is_overlap = 1;
